```typescript
// Lines 1125-1280
async function runSubagent(
  specialist: Specialist,
  task: string,
  cwd: string,
  parentCtx?: SubagentContext,   // { modelRegistry?, model? }
  signal?: AbortSignal,
  onUpdate?: (update: any) => void,
  orchestratorActivity?: OrchestratorActivity,
): Promise<{ output: string; turns: number }> {
  const authStorage = AuthStorage.create();
  const modelRegistry = parentCtx?.modelRegistry ?? ModelRegistry.inMemory(authStorage);

  // Model resolution priority: specialist.model (format "provider/id") > parent's model > registry fallback
  let model;
  if (specialist.model) { ... getModel(provider, id) }
  else if (parentCtx?.model) { model = parentCtx.model; }
  if (!model) { model = modelRegistry.getAvailable()[0]; }
  if (!model) return { output: "[error] ...", turns: 0 };

  // Subagent guard flags (avoids infinite delegation)
  _batchLoadSubagent++; process.env[SUBAGENT_ENV_KEY] = "1";
  const loader = new DefaultResourceLoader({ cwd, agentDir, systemPromptOverride: () => specialist.systemPrompt });
  await loader.reload();
  // flags cleaned up in finally

  // Creates in-memory session — NO cache config or model compatibility
  const { session } = await createAgentSession({
    cwd, model, tools: specialist.tools, resourceLoader: loader,
    sessionManager: SessionManager.inMemory(cwd), authStorage, modelRegistry,
  });

  // Subscribes to session events → onUpdate callbacks + activity feed
  // session.prompt(task) — runs the subagent
  // Output compressed via compressOutput() then capped at OUTPUT_CAP
}
```

**Key observation**: `createAgentSession()` receives NO cache/compat config. No `cacheOptions`, no `compatConfig`, no session-level cache settings.

### 2. `before_agent_start` handler (orchestrator.ts:1393-1465)

